sp_widget.client_script:
api.controller=function() {
  /* widget controller */
  var c = this;
};

sp_widget.css:
.quick-actions{

    display:flex;
    justify-content:center;
    gap:35px;
    flex-wrap:wrap;
    padding:70px 30px;
    background:linear-gradient(135deg,#f5f7fa,#eef3f8);

}

.card{

    position:relative;
    overflow:hidden;
    width:260px;
    background:#ffffff;
    border-radius:18px;
    padding:35px 30px;
    text-align:center;
    box-shadow:0 10px 25px rgba(15,76,129,.10);
    border-top:6px solid #0F4C81;
    transition:all .4s ease;

}

.card::before{

    content:"";
    position:absolute;
    top:0;
    left:-120%;
    width:100%;
    height:100%;
    background:linear-gradient(
        90deg,
        transparent,
        rgba(255,255,255,.45),
        transparent
    );
    transition:.8s;

}

.card:hover::before{

    left:120%;

}

.card:hover{

    transform:translateY(-12px) scale(1.04);
    box-shadow:0 18px 35px rgba(15,76,129,.18);

}

.icon{

    width:85px;
    height:85px;
    margin:0 auto 22px;
    display:flex;
    align-items:center;
    justify-content:center;
    font-size:42px;
    background:linear-gradient(135deg,#0F4C81,#1E6BB8);
    color:#ffffff;
    border-radius:50%;
    box-shadow:0 8px 18px rgba(15,76,129,.20);
    transition:.4s;

}

.card:hover .icon{

    transform:rotate(12deg) scale(1.12);

}

.card h3{

    margin:12px 0;
    color:#0F4C81;
    font-size:24px;
    font-weight:700;

}

.card p{

    color:#666;
    font-size:15px;
    line-height:1.8;
    min-height:60px;
    margin-bottom:25px;

}

.request-btn{

    display:inline-block;
    padding:13px 28px;
    border-radius:8px;
    text-decoration:none;
    background:linear-gradient(135deg,#D4A017,#F2C94C);
    color:#ffffff;
    font-size:15px;
    font-weight:700;
    letter-spacing:.4px;
    transition:.35s;
    box-shadow:0 8px 18px rgba(212,160,23,.25);

}

.request-btn:hover{

    background:linear-gradient(135deg,#B88A0F,#D4A017);
    color:#ffffff;
    text-decoration:none;
    transform:translateY(-3px);
    box-shadow:0 14px 28px rgba(212,160,23,.35);

}

@media(max-width:992px){

    .quick-actions{

        gap:25px;

    }

    .card{

        width:300px;

    }

}

@media(max-width:768px){

    .quick-actions{

        flex-direction:column;
        align-items:center;
        padding:45px 20px;

    }

    .card{

        width:100%;
        max-width:360px;

    }

}
